#include<bits/stdc++.h>
using namespace std;
int a[100010];
int b[100010];
map<int,int> mp;
int main()
{
    int n,b1,b2,sum=0;
    scanf("%d%d",&n,&b1);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&a[i]);
        if(a[i]==b1)
        {
            b[i]=0;
            b2=i;
        }
    }
    sum=0;
    for(int i=1;i<=n;i++)
    {
        sum=a[i];
        if(sum>b1)
        {
            b[i]=1;
        }
        else if(sum==b1)
        {
            b[i]=0;
        }
        else
        {
            b[i]=-1;
        }
    }
    int ans=0;
    sum=0;
    for(int i=b2;i<=n;i++)
    {
        sum+=b[i];
        mp[sum]++;
    }
    sum=0;
    for(int i=b2;i>=1;i--)
    {
        sum+=b[i];
        ans+=mp[-sum];
    }
    printf("%d",ans);
    return 0;
}
